use std::path::PathBuf;
use thiserror::Error;

pub use anyhow::Context;

#[derive(Error, Debug)]
pub enum FlashError {
    #[error("IO error: {0}")]
    Io(std::io::Error),

    #[error("Parse error in {path}: {cause}")]
    Parse { path: PathBuf, cause: String },

    #[error("Index error: {msg}")]
    Index { msg: String, field: Option<String> },

    #[error("Database error: {operation} on {key}: {cause}")]
    Database {
        operation: String,
        key: String,
        cause: String,
    },

    #[error("Unsupported file format: {format}")]
    UnsupportedFormat { format: String, extension: String },

    #[error("File corrupted or encrypted: {path}")]
    CorruptedFile { path: PathBuf, operation: String },

    #[error("Search error: query '{query}' failed: {cause}")]
    Search { query: String, cause: String },

    #[error("Config error: {key}: {cause}")]
    Config { key: String, cause: String },

    #[error("Archive error: {archive_type} - {operation}: {cause}")]
    Archive {
        archive_type: String,
        operation: String,
        cause: String,
    },

    #[error("Lock poisoned: {lock_name}")]
    PoisonedLock { lock_name: String },

    #[error("Not found: {resource} '{identifier}'")]
    NotFound {
        resource: String,
        identifier: String,
    },
    #[error("{context}: {source}")]
    WithContext {
        context: String,
        source: Box<FlashError>,
    },
}

impl Clone for FlashError {
    fn clone(&self) -> Self {
        match self {
            Self::Io(e) => Self::Io(std::io::Error::new(e.kind(), e.to_string())),
            Self::Parse { path, cause } => Self::Parse {
                path: path.clone(),
                cause: cause.clone(),
            },
            Self::Index { msg, field } => Self::Index {
                msg: msg.clone(),
                field: field.clone(),
            },
            Self::Database {
                operation,
                key,
                cause,
            } => Self::Database {
                operation: operation.clone(),
                key: key.clone(),
                cause: cause.clone(),
            },
            Self::UnsupportedFormat { format, extension } => Self::UnsupportedFormat {
                format: format.clone(),
                extension: extension.clone(),
            },
            Self::CorruptedFile { path, operation } => Self::CorruptedFile {
                path: path.clone(),
                operation: operation.clone(),
            },
            Self::Search { query, cause } => Self::Search {
                query: query.clone(),
                cause: cause.clone(),
            },
            Self::Config { key, cause } => Self::Config {
                key: key.clone(),
                cause: cause.clone(),
            },
            Self::Archive {
                archive_type,
                operation,
                cause,
            } => Self::Archive {
                archive_type: archive_type.clone(),
                operation: operation.clone(),
                cause: cause.clone(),
            },
            Self::PoisonedLock { lock_name } => Self::PoisonedLock {
                lock_name: lock_name.clone(),
            },
            Self::NotFound {
                resource,
                identifier,
            } => Self::NotFound {
                resource: resource.clone(),
                identifier: identifier.clone(),
            },
            Self::WithContext { context, source } => Self::WithContext {
                context: context.clone(),
                source: source.clone(),
            },
        }
    }
}

impl From<std::io::Error> for FlashError {
    fn from(e: std::io::Error) -> Self {
        FlashError::Io(e)
    }
}

pub trait Contextualize<T> {
    fn context(self, msg: &str) -> std::result::Result<T, FlashError>;
}

impl<T, E: Into<FlashError>> Contextualize<T> for std::result::Result<T, E> {
    fn context(self, msg: &str) -> std::result::Result<T, FlashError> {
        self.map_err(|e| FlashError::WithContext {
            context: msg.to_string(),
            source: Box::new(e.into()),
        })
    }
}

pub type Result<T> = std::result::Result<T, FlashError>;

// Helper constructors for common error patterns
impl FlashError {
    pub fn parse<P: Into<PathBuf>, S: Into<String>>(path: P, cause: S) -> Self {
        Self::Parse {
            path: path.into(),
            cause: cause.into(),
        }
    }

    pub fn index<S: Into<String>>(msg: S) -> Self {
        Self::Index {
            msg: msg.into(),
            field: None,
        }
    }

    pub fn index_field<S: Into<String>>(field: S, msg: S) -> Self {
        Self::Index {
            msg: msg.into(),
            field: Some(field.into()),
        }
    }

    pub fn database<S: Into<String>, S2: Into<String>>(operation: S, key: S, cause: S2) -> Self {
        Self::Database {
            operation: operation.into(),
            key: key.into(),
            cause: cause.into(),
        }
    }

    pub fn unsupported_format<S: Into<String>>(format: S, extension: S) -> Self {
        Self::UnsupportedFormat {
            format: format.into(),
            extension: extension.into(),
        }
    }

    pub fn corrupted_file<P: Into<PathBuf>, S: Into<String>>(path: P, operation: S) -> Self {
        Self::CorruptedFile {
            path: path.into(),
            operation: operation.into(),
        }
    }

    pub fn search<S1: Into<String>, S2: Into<String>>(query: S1, cause: S2) -> Self {
        Self::Search {
            query: query.into(),
            cause: cause.into(),
        }
    }

    pub fn config<S1: Into<String>, S2: Into<String>>(key: S1, cause: S2) -> Self {
        Self::Config {
            key: key.into(),
            cause: cause.into(),
        }
    }

    pub fn archive<S1: Into<String>, S2: Into<String>, S3: Into<String>>(
        archive_type: S1,
        operation: S2,
        cause: S3,
    ) -> Self {
        Self::Archive {
            archive_type: archive_type.into(),
            operation: operation.into(),
            cause: cause.into(),
        }
    }

    pub fn poisoned_lock<S: Into<String>>(lock_name: S) -> Self {
        Self::PoisonedLock {
            lock_name: lock_name.into(),
        }
    }

    pub fn not_found<S: Into<String>>(resource: S, identifier: S) -> Self {
        Self::NotFound {
            resource: resource.into(),
            identifier: identifier.into(),
        }
    }
}

impl From<tantivy::TantivyError> for FlashError {
    fn from(e: tantivy::TantivyError) -> Self {
        FlashError::Index {
            msg: e.to_string(),
            field: None,
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_error_display() {
        let err = FlashError::parse("/test/file.pdf", "Invalid PDF structure");
        assert_eq!(
            err.to_string(),
