            ptype: ProgressType::Content,
            files_per_second: 10.5,
            eta_seconds: 5,
            current_folder: "/home/user".to_string(),
        };
        let json = serde_json::to_string(&event).unwrap();
        assert!(json.contains("test.txt"));
        assert!(json.contains("Content"));
    }
}

